/*
 * Caution: This file is auto-generated from the problem statement and plan.
 * It implements the solve function to fix the failure_mode_first strategy issue.
 */

const { sql } = require('slonik');

async function solve({ difficulty, limit = 50, tags }) {
  // Normalize tags input: accept comma-separated string or array, case-insensitive
  let normalizedTags = [];
  if (tags) {
    if (Array.isArray(tags)) {
      // flatten comma-separated strings inside array elements
      normalizedTags = tags
        .flatMap(t => t.split(','))
        .map(t => t.trim().toLowerCase())
        .filter(t => t.length > 0);
    } else if (typeof tags === 'string') {
      normalizedTags = tags
        .split(',')
        .map(t => t.trim().toLowerCase())
        .filter(t => t.length > 0);
    }
  }

  // Build query parts
  const conditions = [];
  const params = {};

  if (difficulty) {
    conditions.push(sql`difficulty = ${difficulty}`);
  }

  if (normalizedTags.length > 0) {
    // Use array containment to filter problems that have all tags
    conditions.push(sql`tags @> ${normalizedTags}`);
  }

  const whereClause = conditions.length > 0 ? sql`WHERE ${sql.join(conditions, sql` AND `)}` : sql``;

  // Query problems with stable sorting by problem_id
  const query = sql`
    SELECT problem_id, title, difficulty, tags
    FROM problems
    ${whereClause}
    ORDER BY problem_id
    LIMIT ${limit}
  `;

  const problems = await sql.query(query);

  // Return problems and metadata with normalized tags
  return {
    problems,
    metadata: {
      filters: {
        difficulty: difficulty || null,
        tags: normalizedTags.length > 0 ? normalizedTags : null,
      },
    },
  };
}

module.exports = { solve };
